+        "SELECT name FROM customers_sq WHERE id <= (SELECT MAX(customer_id) FROM orders_sq) ORDER BY name",
+    ];
+
+    let mismatches = oracle_compare(&fconn, &rconn, &queries);
+    if !mismatches.is_empty() {
